const verifyCookie = async (cookie, value, keystore) => {
  if (!value) {
    return undefined;
  }
  let signature;
  [value, signature] = value.split('.');
  if (await verifySignature(cookie, value, signature, keystore)) {
    return value;
  }

  return undefined;
};

function encodeState(stateObject = {}) {
  // this filters out nonce, code_verifier, and max_age from the state object so that the values are
  // only stored in its dedicated transient cookie
  const { nonce, code_verifier, max_age, ...filteredState } = stateObject;
  return base64url.encode(JSON.stringify(filteredState));
}

function NativeCollection(name, conn, options) {
  this.collection = null;
  this.Promise = options.Promise || Promise;
  this.modelName = options.modelName;
  delete options.modelName;
  this._closed = false;
  MongooseCollection.apply(this, arguments);
}

toJSONSchema(options) {
  const embeddedSchemaType = this.getEmbeddedSchemaType();

  const result = this._createJSONSchemaTypeDefinition('object', 'object', options);
  result.additionalProperties = embeddedSchemaType.toJSONSchema(options);

  return result;
}

async *loader({ config }) {
  if (config.getString('catalog.role') !== 'write') {
    return;
  }

  // Here inside the loader, you can add more features that you want to
  // apply to ONLY the write nodes, as needed. This is where providers and
  // processors go, for example. The incremental ingestion provider line
  // below is just an example.
  yield import(
    '@backstage/plugin-catalog-backend-module-incremental-ingestion'
  );
}

function notAllowedMessage(url: string) {
  return (
    `Reading from '${url}' is not allowed. ` +
    `You may need to configure an integration for the target host, or add it ` +
    `to the configured list of allowed hosts at 'backend.reading.allow'`
  );
}

get request(): RequestValidatorOptions {
  const { allErrors, allowUnknownQueryParameters, coerceTypes, removeAdditional, discriminator } = <
    ValidateRequestOpts
  >this.options.validateRequests;
  return {
    ...this.baseOptions(),
    allErrors,
    allowUnknownQueryParameters,
    coerceTypes,
    removeAdditional,
    discriminator,
  };
}

function openapiValidator(options: OpenApiValidatorOpts) {
  const oav = new OpenApiValidator(options);
  exports.middleware._oav = oav;

  return oav.installMiddleware(
    new OpenApiSpecLoader({
      apiDoc: cloneDeep(options.apiSpec),
      validateApiSpec: options.validateApiSpec,
      $refParser: options.$refParser,
    }).load(),
  );
}

