protected getSequelizeOperator(key: keyof typeof operatorTranslations) {
  const sequelizeOperator = operatorTranslations[key];
  if (!sequelizeOperator) {
    throw Error(`There is no equivalent operator for "${key}" in sequelize.`);
  }
  return sequelizeOperator;
}

public Generate(): Tsoa.Metadata {
  this.extractNodeFromProgramSourceFiles();

  const controllers = this.buildControllers();

  this.checkForMethodSignatureDuplicates(controllers);
  this.checkForPathParamSignatureDuplicates(controllers);

  return {
    controllers,
    referenceTypeMap: this.referenceTypeMap,
  };
}

export function ensureOptionsAreImmutable<T extends object>(options: T): T {
  if (isDevEnv()) {
    // Users should not mutate any mutable value inside `options`, and instead mutate the `options` object directly
    // This ensures `options` remains immutable while limiting ourselves to a shallow clone in production,
    // improving performance.
    return freezeDescendants(cloneDeepPlainValues(options, true));
  }

  return options;
}

protected async bootstrap(container: Container = createContainer()) {
  // Clone all providers in the container
  this.addProviders(container);

  // Resolve all configuration
  await this.resolveConfiguration();

  // allow mocking or changing provider instance before loading injector
  this.resolveImportsProviders();

  return this;
}

export function getMetadataArgsStorage(): MetadataArgsStorage {
  if (!(global as any).routingControllersMetadataArgsStorage)
    (global as any).routingControllersMetadataArgsStorage = new MetadataArgsStorage();

  return (global as any).routingControllersMetadataArgsStorage;
}
